mapper.select:
SELECT COUNT(*)
  FROM collaboration_friendship
 WHERE user_id = #{userId}
   AND friend_user_id = #{friendUserId}

SELECT *
  FROM collaboration_friend_request
 WHERE id = #{id}

SELECT id
  FROM collaboration_conversation
 WHERE type = 'DIRECT'
   AND user_low_id = #{userLowId}
   AND user_high_id = #{userHighId}
 LIMIT 1

SELECT *
  FROM collaboration_conversation
 WHERE id = #{id}

SELECT COUNT(*)
  FROM collaboration_conversation_invite
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.update:
UPDATE collaboration_conversation_invite
   SET status = 'ACCEPTED',
       responded_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.select:
SELECT COUNT(*)
  FROM collaboration_conversation_member
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

SELECT COUNT(*)
  FROM collaboration_conversation_ban
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND (banned_until IS NULL OR banned_until > NOW())

mapper.update:
UPDATE collaboration_conversation_member
   SET muted = #{muted}
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

UPDATE collaboration_conversation
   SET updated_at = NOW()
 WHERE id = #{conversationId}

UPDATE collaboration_conversation_member
   SET last_read_message_id = GREATEST(COALESCE(last_read_message_id, 0), #{messageId}),
       last_read_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

mapper.select:
SELECT last_seen_at
  FROM user_desktop_presence
 WHERE user_id = #{userId}

SELECT id, user_id, nickname, avatar_url, description, is_default AS default_profile, created_at, updated_at
  FROM user_chat_profile
 WHERE id = #{id}
   AND user_id = #{userId}
 LIMIT 1

mapper.update:
UPDATE user_chat_profile
   SET is_default = 0
 WHERE user_id = #{userId}

UPDATE user_chat_profile
   SET nickname = #{nickname},
       avatar_url = #{avatarUrl},
       description = #{description},
       is_default = #{defaultProfile}
 WHERE id = #{id}
   AND user_id = #{userId}

mapper.delete:
DELETE FROM user_chat_profile
 WHERE id = #{id}
   AND user_id = #{userId}
